 * Returns the associated color string for a given category.
 * Provides a fallback color if the category is not found.
 */
export function getCategoryColor(category: string): string {
  const entry = CATEGORY_COLORS.find((c) => c.name === category);
  return entry ? entry.color : 'var(--ggui-color-gray-500)';
}


