// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { elements } = props;

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<HookReturn['selectedElement']>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(
    () => [
      { name: 'alkali-metal', color: 'var(--ggui-color-primary)' },
      { name: 'alkaline-earth-metal', color: 'var(--ggui-color-secondary)' },
      { name: 'transition-metal', color: 'var(--ggui-color-accent)' },
      { name: 'post-transition-metal', color: 'var(--ggui-color-info)' },
      { name: 'metalloid', color: 'var(--ggui-color-success)' },
      { name: 'nonmetal', color: 'var(--ggui-color-warning)' },
      { name: 'halogen', color: 'var(--ggui-color-danger)' },
      { name: 'noble-gas', color: 'var(--ggui-color-neutral)' },
    ],
    []
  );

  const handleSelect = useCallback((element: HookReturn['selectedElement']) => {
    setSelectedElement(element);
  }, []);

  return {
    filteredElements,
    selectedElement,
    searchQuery,
    setSearchQuery,
    handleSelect,
    categories,
  };
}


