import { ProfileData } from '/virtual/types';

export const DEFAULT_PROFILE: ProfileData = {
  name: '',
  email: '',
  avatar: '',
  role: '',
  emailNotifications: false,
  theme: 'light',
};

export const STEP_LABELS = ['Profile Details', 'Preferences', 'Review'];
export const TOTAL_STEPS = 3;
export const THEME_OPTIONS = ['light', 'dark'];
export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const isStepValid = (step: number, data: ProfileData): boolean => {
  if (step === 0) {
    return data.name.trim() !== '' && EMAIL_REGEX.test(data.email);
  }
  if (step === 1) return true;
  if (step === 2) return true;
  return false;
};

