import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}

export function useComponent(props: Props): HookReturn {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [profileData, setProfileData] = useState<ProfileData>(() => ({
    name: initialProfile?.name || "",
    email: initialProfile?.email || "",
    avatar: initialProfile?.avatar || "",
    role: initialProfile?.role || roleOptions[0] || "",
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || "light",
  }));

  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return !(
        profileData.name.trim() !== "" &&
        emailRegex.test(profileData.email) &&
        profileData.avatar !== ""
      );
    }
    return false;
  }, [currentStep, profileData]);

  const updateField = useCallback(<K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setProfileData((prev) => ({ ...prev, [field]: value }));
  }, []);

  const goToNext = useCallback(() => {
    setCurrentStep((prev) => Math.min(prev + 1, 3));
  }, []);

  const goToBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(prev - 1, 1));
  }, []);

  const submit = useCallback(() => {
    onComplete(profileData);
  }, [profileData, onComplete]);

  return {
    currentStep,
    profileData,
    isNextDisabled,
    updateField,
    goToNext,
    goToBack,
    submit,
  };
}


