import type { Props, HookReturn } from '/virtual/types';
import React from 'react';
import { Stack, Box, Text, Progress, Button } from '@ggui-ai/design/primitives';

export const StepIndicator = ({ currentStep, totalSteps }: StepIndicatorProps) => {
  const percentage = (currentStep / totalSteps) * 100;
  return (
    <Box padding="var(--ggui-spacing-4)">
      <Stack direction="vertical" gap="var(--ggui-spacing-2)">
        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of {totalSteps}
          </Text>
        </div>
        <Progress value={percentage} max={100} variant="default" />
      </Stack>
    </Box>
  );
};

export function MainView(props: any) {
  const { currentStep, goToNext, goToBack, submit } = props;
  const totalSteps = 3;

  return (
    <div style={{ padding: 'var(--ggui-spacing-4)' }}>
      <StepIndicator currentStep={currentStep} totalSteps={totalSteps} />
      {/* Main content area */}
      <div style={{ marginTop: 'var(--ggui-spacing-4)' }}>
        {currentStep === 1 && <div>Profile Form Placeholder</div>}
        {currentStep === 2 && <div>Preference Form Placeholder</div>}
        {currentStep === 3 && <div>Review Summary Placeholder</div>}
      </div>
      {/* Actions */}
      <div style={{ marginTop: 'var(--ggui-spacing-4)', display: 'flex', gap: 'var(--ggui-spacing-2)' }}>
        {currentStep > 1 && <Button variant="secondary" onClick={goToBack}>Back</Button>}
        {currentStep < 3 ? <Button onClick={goToNext}>Next</Button> : <Button onClick={submit}>Submit</Button>}
      </div>
    </div>
  );
}


