import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function MainView(props: Props & HookReturn) {
  const { initialProfile, avatarOptions, roleOptions, onComplete, currentStep, profileData, isNextDisabled, updateField, goToNext, goToBack, submit } = props;

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding</Heading>
        <Progress value={(currentStep - 1) * 50} max={100} />
        <Card padding={24} shadow="md">
          <Box paddingY={16}>
            {currentStep === 1 && (
              <Stack gap={16}>
                <Input label="Name" value={profileData.name} onChange={(v) => updateField('name', v)} />
                <Input label="Email" value={profileData.email} onChange={(v) => updateField('email', v)} />
                <Select label="Avatar" value={profileData.avatar} onChange={(v) => updateField('avatar', v)} options={avatarOptions.map(a => ({ value: a, label: a }))} />
              </Stack>
            )}
            {currentStep === 2 && (
              <Stack gap={16}>
                <Select label="Role" value={profileData.role} onChange={(v) => updateField('role', v)} options={roleOptions.map(r => ({ value: r, label: r }))} />
                <Toggle label="Email Notifications" checked={profileData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              </Stack>
            )}
            {currentStep === 3 && <Text>Review: {profileData.name} ({profileData.email}) - {profileData.role}</Text>}
          </Box>
          <Row justify="between" style={{ marginTop: 'var(--ggui-spacing-6)' }}>
            <Button variant="ghost" onClick={goToBack} disabled={currentStep === 1}>Back</Button>
            <Button onClick={currentStep === 3 ? submit : goToNext} disabled={currentStep === 1 && isNextDisabled}>{currentStep === 3 ? 'Complete' : 'Next'}</Button>
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}


